// isNilOrEmpty checks whether a JSON object has nil or empty values for
// common identifier fields (title, name, identifier, id).
func isNilOrEmpty(raw json.RawMessage) bool {
	var obj map[string]interface{}
	if err := json.Unmarshal(raw, &obj); err != nil {
		return true
	}
	for _, key := range []string{"title", "name", "identifier", "id"} {
		if v, ok := obj[key]; ok {
			if v == nil {
				continue
			}
			if s, ok := v.(string); ok && strings.TrimSpace(s) != "" {
				return false
			}
			// Non-string, non-nil value (e.g. numeric ID) — keep it
			if _, ok := v.(string); !ok {
				return false
			}
		}
	}
	return true
}

func newSearchCmd(flags *rootFlags) *cobra.Command {
	var resourceType string
	var limit int
	var dbPath string

	cmd := &cobra.Command{
		Use:   "search <query>",
		Short: "Full-text search across locally synced data",
		Long: `Search locally cached data using FTS5 full-text search.
Data must be synced first with the sync command. Searches are instant
(millisecond-fast) since they query local SQLite, not the remote API.`,
		Example: `  # Search all synced data
  dub-pp-cli search "error timeout"

  # Search a specific resource type
  dub-pp-cli search "payment failed" --type transactions

  # JSON output for piping
  dub-pp-cli search "critical" --json --limit 20`,
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			query := args[0]

			if dbPath == "" {
				home, _ := os.UserHomeDir()
				dbPath = filepath.Join(home, ".local", "share", "dub-pp-cli", "data.db")
			}

			db, err := store.Open(dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w\nRun 'dub-pp-cli sync' first to populate the local database.", err)
			}
			defer db.Close()

			var results []json.RawMessage
			switch resourceType {
			case "folders":
				results, err = db.SearchFolders(query, limit)
			case "links":
				results, err = db.SearchLinks(query, limit)
			case "partners":
				results, err = db.SearchPartners(query, limit)
			case "":
				// Search all FTS-enabled tables individually to avoid duplicates.
				// Do NOT use db.Search() here — it queries resources_fts which
				// overlaps with per-table FTS indexes and causes duplicate results.
				seen := make(map[string]bool)
				_ = seen // prevent unused error when no FTS tables exist
				{
					partial, searchErr := db.SearchFolders(query, limit)
					if searchErr != nil {
						return fmt.Errorf("search folders failed: %w", searchErr)
					}
					for _, r := range partial {
						key := string(r)
						if !seen[key] {
							seen[key] = true
							results = append(results, r)
						}
					}
				}
				{
					partial, searchErr := db.SearchLinks(query, limit)
					if searchErr != nil {
						return fmt.Errorf("search links failed: %w", searchErr)
					}
					for _, r := range partial {
						key := string(r)
						if !seen[key] {
							seen[key] = true
							results = append(results, r)
						}
					}
				}
				{
					partial, searchErr := db.SearchPartners(query, limit)
					if searchErr != nil {
						return fmt.Errorf("search partners failed: %w", searchErr)
					}
					for _, r := range partial {
						key := string(r)
						if !seen[key] {
							seen[key] = true
							results = append(results, r)
						}
					}
				}
			default:
				// Unrecognized type — fall back to generic search
				results, err = db.Search(query, limit)
			}
			if err != nil {
				return fmt.Errorf("search failed: %w", err)
			}

			// Filter out entries with nil or empty identifier fields.
			filtered := make([]json.RawMessage, 0, len(results))
			for _, r := range results {
				if !isNilOrEmpty(r) {
					filtered = append(filtered, r)
				}
			}
			results = filtered

			// Enforce limit across aggregated results.
			if len(results) > limit {
				results = results[:limit]
			}

			if len(results) == 0 {
				fmt.Fprintf(os.Stderr, "No results for %q\n", query)
				return nil
			}

			if flags.asJSON {
				enc := json.NewEncoder(os.Stdout)
				enc.SetIndent("", "  ")
				return enc.Encode(results)
			}

			for _, r := range results {
				fmt.Println(string(r))
			}
			return nil
		},
	}

	cmd.Flags().StringVar(&resourceType, "type", "", "Filter by resource type")
	cmd.Flags().IntVar(&limit, "limit", 50, "Maximum results to return")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: ~/.local/share/dub-pp-cli/data.db)")

	return cmd
}
